use anchor_lang::prelude::*;
use anchor_spl::{
    associated_token::AssociatedToken,
    token::{self, AuthorityType, Mint, MintTo, SetAuthority, Token, TokenAccount, Transfer},
};

// Run `anchor keys sync` after generating the deployment keypair.
declare_id!("Fg6PaFpoGXkYsidMpWxTWqkZVY6W2BeZ7FEfcYkgMQhg");

const STATUS_TRADING: u8 = 0;
const STATUS_MIGRATION_READY: u8 = 1;
const STATUS_MIGRATING: u8 = 2;
const STATUS_ASSETS_WITHDRAWN: u8 = 3;
const STATUS_MIGRATED: u8 = 4;
const BPS_DENOMINATOR: u128 = 10_000;
const TOKEN_DECIMALS: u8 = 6;

#[program]
pub mod core_launchpad {
    use super::*;

    pub fn initialize_config(
        ctx: Context<InitializeConfig>,
        migration_authority: Pubkey,
        fee_receiver: Pubkey,
        core_mint: Pubkey,
        migration_threshold_lamports: u64,
        fee_bps: u16,
    ) -> Result<()> {
        require!(migration_threshold_lamports > 0, LaunchpadError::InvalidThreshold);
        require!(fee_bps <= 1_000, LaunchpadError::FeeTooHigh);

        let config = &mut ctx.accounts.global;
        config.admin = ctx.accounts.admin.key();
        config.migration_authority = migration_authority;
        config.fee_receiver = fee_receiver;
        config.core_mint = core_mint;
        config.migration_threshold_lamports = migration_threshold_lamports;
        config.fee_bps = fee_bps;
        config.bump = ctx.bumps.global;

        emit!(ConfigInitialized {
            admin: config.admin,
            migration_authority,
            fee_receiver,
            core_mint,
            migration_threshold_lamports,
            fee_bps,
        });
        Ok(())
    }

    pub fn update_config(
        ctx: Context<UpdateConfig>,
        migration_authority: Pubkey,
        fee_receiver: Pubkey,
        migration_threshold_lamports: u64,
        fee_bps: u16,
    ) -> Result<()> {
        require!(migration_threshold_lamports > 0, LaunchpadError::InvalidThreshold);
        require!(fee_bps <= 1_000, LaunchpadError::FeeTooHigh);

        let config = &mut ctx.accounts.global;
        config.migration_authority = migration_authority;
        config.fee_receiver = fee_receiver;
        config.migration_threshold_lamports = migration_threshold_lamports;
        config.fee_bps = fee_bps;
        Ok(())
    }

    #[allow(clippy::too_many_arguments)]
    pub fn create_launch(
        ctx: Context<CreateLaunch>,
        name: String,
        symbol: String,
        uri: String,
        total_supply: u64,
        curve_token_allocation: u64,
        migration_token_allocation: u64,
        initial_virtual_sol_reserves: u64,
        initial_virtual_token_reserves: u64,
    ) -> Result<()> {
        require!(name.as_bytes().len() <= 32, LaunchpadError::NameTooLong);
        require!(symbol.as_bytes().len() <= 10, LaunchpadError::SymbolTooLong);
        require!(uri.as_bytes().len() <= 200, LaunchpadError::UriTooLong);
        require!(ctx.accounts.mint.decimals == TOKEN_DECIMALS, LaunchpadError::InvalidDecimals);
        require!(ctx.accounts.mint.supply == 0, LaunchpadError::MintAlreadyUsed);
        require!(
            ctx.accounts.mint.freeze_authority == anchor_lang::solana_program::program_option::COption::None,
            LaunchpadError::InvalidFreezeAuthority
        );
        require!(total_supply > 0, LaunchpadError::InvalidSupply);
        require!(curve_token_allocation > 0, LaunchpadError::InvalidSupply);
        require!(migration_token_allocation > 0, LaunchpadError::InvalidSupply);

require!(
     curve_token_allocation
         .checked_add(migration_token_allocation)
         .ok_or(LaunchpadError::MathOverflow)? == total_supply,
     LaunchpadError::InvalidAllocation
 );
 require!(initial_virtual_sol_reserves > 0, LaunchpadError::InvalidVirtualReserves);
 require!(
     initial_virtual_token_reserves >= curve_token_allocation,
     LaunchpadError::InvalidVirtualReserves
 );
 // A creator cannot choose reserves that exhaust the curve before the
 // globally configured graduation target can be reached.
 let tokens_required_at_threshold = quote_buy(
     initial_virtual_sol_reserves,
     initial_virtual_token_reserves,
     ctx.accounts.global.migration_threshold_lamports,
 )?;
 require!(
     tokens_required_at_threshold <= curve_token_allocation,
     LaunchpadError::CurveCannotReachThreshold
 );

 let curve = &mut ctx.accounts.curve;
 curve.creator = ctx.accounts.creator.key();
 curve.mint = ctx.accounts.mint.key();
 curve.token_vault = ctx.accounts.token_vault.key();
 curve.name = name;
 curve.symbol = symbol;
 curve.uri = uri;
 curve.total_supply = total_supply;
 curve.curve_token_allocation = curve_token_allocation;
 curve.migration_token_allocation = migration_token_allocation;
 curve.migration_authority = ctx.accounts.global.migration_authority;
 curve.fee_receiver = ctx.accounts.global.fee_receiver;
 curve.migration_threshold_lamports = ctx.accounts.global.migration_threshold_lamports;
 curve.fee_bps = ctx.accounts.global.fee_bps;
 curve.virtual_sol_reserves = initial_virtual_sol_reserves;
 curve.virtual_token_reserves = initial_virtual_token_reserves;
 curve.real_sol_reserves = 0;
 curve.real_token_reserves = curve_token_allocation;
 curve.migration_token_reserves = migration_token_allocation;
 curve.withdrawn_sol_amount = 0;
 curve.withdrawn_token_amount = 0;
 curve.migrated_core_amount = 0;
 curve.migrated_token_amount = 0;
 curve.status = STATUS_TRADING;
 curve.migration_pool = Pubkey::default();
 curve.created_at = Clock::get()?.unix_timestamp;
 curve.bump = ctx.bumps.curve;

 token::mint_to(
     CpiContext::new(
         ctx.accounts.token_program.to_account_info(),
         MintTo {
             mint: ctx.accounts.mint.to_account_info(),
             to: ctx.accounts.token_vault.to_account_info(),
             authority: ctx.accounts.creator.to_account_info(),
         },
     ),
     total_supply,
 )?;

 // Supply is fixed at launch. This removes the creator's ability to mint later.
 token::set_authority(
     CpiContext::new(
         ctx.accounts.token_program.to_account_info(),
         SetAuthority {
             account_or_mint: ctx.accounts.mint.to_account_info(),
             current_authority: ctx.accounts.creator.to_account_info(),
         },
     ),
     AuthorityType::MintTokens,
     None,
 )?;

 emit!(LaunchCreated {
     curve: curve.key(),
     mint: curve.mint,
     creator: curve.creator,
     total_supply,
     curve_token_allocation,
